+uint64_t GenerateSampleSalt()
+{
+    std::random_device rd;
+    uint64_t salt = (static_cast<uint64_t>(rd()) << kSaltHighShift) | static_cast<uint64_t>(rd());
+    if (salt == 0) {
+        // Fallback: PID + steady_clock hash
