+uint64_t BuildThreshold(uint32_t ppm)
+{
+    if (ppm == 0) {
+        return 0;
+    }
+    if (ppm == kSamplePpmBase) {
+        return kAlwaysSampleThreshold;
+    }
+    return static_cast<uint64_t>(
+        (static_cast<unsigned __int128>(ppm) * UINT64_MAX) / kSamplePpmBase);
